import { inject, Injectable } from '@angular/core';
import {
  HttpBackend,
  HttpClient,
  HttpHeaders,
  HttpParams,
} from '@angular/common/http';
import {
  catchError,
  concatMap,
  delay,
  forkJoin,
  from,
  map,
  Observable,
  of,
  switchMap,
  tap,
  toArray,
} from 'rxjs';
import { environment } from '../../../../environments/environment';
import {
  AssetCreateRequest,
  AssetResponse,
  AssetUpdateRequest,
  AuthUserResponse,
  ClientListItem,
  DeviceCreateRequest,
  DeviceResponse,
  DeviceUpdateRequest,
  EntitiesService,
  SelectedUserTokenResponse,
  SimCardCreateRequest,
  SimCardResponse,
  SimCardUpdateRequest,
  UserSessionResponse,
} from '../../../api';
import { isDefined, isNullOrUndefined } from '../../../shared/utils';

export interface KeyTelematicsSyncResult {
  success: boolean;
  message: string;
}

export interface EntityCheckItem {
  type: 'asset' | 'device' | 'simCard';
  label: string;
  existingId: string | null;
  conflict?: boolean;
  conflictOwnerName?: string;
}

export interface DeviceSyncPlan {
  device: DeviceResponse;
  simCard: SimCardResponse | null;
  existingKtDeviceId: string | null;
  existingKtSimCardId: string | null;
  deviceConflict?: boolean;
  deviceConflictOwnerName?: string;
}

export interface SyncPlan {
  asset: AssetResponse;
  devicePlans: DeviceSyncPlan[];
  entityChecks: EntityCheckItem[];
}

// Resolved KT IDs keyed by `${depType}:${sourceEntityName}`
export type ResolvedIds = Map<string, string>;

// CypherView device ID → KT device ID (user-selected existing device to update; absent = create new)
export type KtDeviceSelections = Map<string, string>;

// CypherView device ID → KT device type ID (override when CV device type not found in KT)
export type KtDeviceTypeOverrides = Map<string, string>;

interface KeyTelematicsLoginState {
  accessToken: string;
  ownerContextId: string;
  accounts: AuthUserResponse[];
}

@Injectable({ providedIn: 'root' })
export class KeyTelematicsSyncService {
  private readonly http = new HttpClient(inject(HttpBackend));
  private readonly entitiesService = inject(EntitiesService);
  private readonly keyTelematicsApiUrl = environment.keyTelematicsApiUrl;

  private static readonly SESSION_KEY = 'kt_login_state';

  private loginState: KeyTelematicsLoginState | null = (() => {
    try {
      const raw = sessionStorage.getItem(KeyTelematicsSyncService.SESSION_KEY);
      return isDefined(raw)
        ? (JSON.parse(raw) as KeyTelematicsLoginState)
        : null;
    } catch {
      return null;
    }
  })();

  get isAuthenticated(): boolean {
    return this.loginState !== null && !!this.loginState.ownerContextId;
  }

  getAccounts(): AuthUserResponse[] {
    return this.loginState?.accounts ?? [];
  }

  getSelectedAccount(): AuthUserResponse | null {
    if (isNullOrUndefined(this.loginState?.ownerContextId)) return null;
    return (
      (this.loginState.accounts ?? []).find(
        (u) => u.owner.id === this.loginState?.ownerContextId,
      ) ?? null
    );
  }

  selectAccount(user: AuthUserResponse): Observable<void> {
    return this.http
      .get<SelectedUserTokenResponse>(
        `${this.keyTelematicsApiUrl}/auth/select/user/${user.id}`,
        { headers: this.buildHeaders() },
      )
      .pipe(
        tap((response) => {
          this.loginState = {
            accessToken: response.accessToken,
            ownerContextId: user.owner.id,
            accounts: this.loginState?.accounts ?? [],
          };
          sessionStorage.setItem(
            KeyTelematicsSyncService.SESSION_KEY,
            JSON.stringify(this.loginState),
          );
        }),
        map(() => undefined),
        catchError((err) => {
          if (err?.status === 401) this.clearToken();
          throw err;
        }),
      );
  }

  clearToken(): void {
    this.loginState = null;
    sessionStorage.removeItem(KeyTelematicsSyncService.SESSION_KEY);
  }

  login(username: string, password: string): Observable<UserSessionResponse> {
    return this.http
      .post<UserSessionResponse>(`${this.keyTelematicsApiUrl}/auth/signin`, {
        username,
        password,
      })
      .pipe(
        tap((response) => {
          const users = response.users ?? [];
          if (users.length === 0)
            throw new Error('No user returned from Key Telematics login.');
          // Auto-select when there is only one account; leave empty for the
          // component to prompt account selection when multiple accounts exist.
          const autoSelected = users.length === 1 ? users[0] : null;
          this.loginState = {
            accessToken: response.accessToken,
            ownerContextId: autoSelected?.owner.id ?? '',
            accounts: users,
          };
          sessionStorage.setItem(
            KeyTelematicsSyncService.SESSION_KEY,
            JSON.stringify(this.loginState),
          );
        }),
      );
  }

  // ── Session ───────────────────────────────────────────────────────────────

  verifySession(): Observable<boolean> {
    if (!this.loginState) return of(false);
    return this.http
      .get<{ items: unknown[] }>(
        `${this.keyTelematicsApiUrl}/accounts/clients`,
        {
          headers: this.buildHeaders(),
          params: new HttpParams()
            .set('owner', this.loginState.ownerContextId)
            .set('limit', '1'),
        },
      )
      .pipe(
        map(() => true),
        catchError((err) => {
          if (err?.status === 401) this.clearToken();
          return of(false);
        }),
      );
  }

  // ── Search ────────────────────────────────────────────────────────────────

  searchClients(term: string): Observable<ClientListItem[]> {
    if (!this.loginState) return of([]);
    return this.searchEntities<ClientListItem>(
      'accounts/clients',
      term,
      this.loginState.ownerContextId,
    );
  }

  searchAssetTypes(
    term: string,
    clientId: string,
  ): Observable<{ id: string; name: string }[]> {
    return this.searchEntities('entities/assettypes', term, clientId);
  }

  searchCostCentres(
    term: string,
    clientId: string,
  ): Observable<{ id: string; name: string }[]> {
    return this.searchEntities('entities/costcentres', term, clientId);
  }

  searchGroups(
    term: string,
    clientId: string,
  ): Observable<{ id: string; name: string }[]> {
    return this.searchEntities('entities/assetgroups', term, clientId);
  }

  searchCategories(
    term: string,
    clientId: string,
  ): Observable<{ id: string; name: string }[]> {
    return this.searchEntities('entities/assetcategories', term, clientId);
  }

  searchDeviceTypes(
    term: string,
    clientId: string,
  ): Observable<{ id: string; name: string }[]> {
    return this.searchEntities('entities/devicetypes', term, clientId);
  }

  searchKtDevices(
    term: string,
    clientId: string,
  ): Observable<{ id: string; name: string }[]> {
    return this.searchEntities('entities/devices', term, clientId);
  }

  // ── Fetch ─────────────────────────────────────────────────────────────────

  fetchDevices(asset: AssetResponse): Observable<DeviceResponse[]> {
    const deviceIds = (asset.devices ?? [])
      .map((d) => d.id)
      .filter((id): id is string => !!id);

    if (deviceIds.length === 0) return of([]);

    return forkJoin(
      deviceIds.map((id) =>
        this.entitiesService.getDevice(id).pipe(catchError(() => of(null))),
      ),
    ).pipe(
      map((results) => results.filter((d): d is DeviceResponse => d !== null)),
    );
  }

  // ── Check ─────────────────────────────────────────────────────────────────

  checkEntities(
    asset: AssetResponse,
    devices: DeviceResponse[],
    keyTelematicsClientId: string,
    ktDeviceSelections: KtDeviceSelections,
    ktDeviceTypeOverrides: KtDeviceTypeOverrides,
  ): Observable<SyncPlan> {
    if (!this.loginState) {
      return of({ asset, devicePlans: [], entityChecks: [] });
    }

    const headers = this.buildHeaders();
    const assetsUrl = `${this.keyTelematicsApiUrl}/entities/assets`;
    const simCardsUrl = `${this.keyTelematicsApiUrl}/entities/simcards`;

    const assetCheck$ = this.findByName<{ id?: string }>(
      assetsUrl,
      asset.name ?? '',
      keyTelematicsClientId,
      headers,
    );

    const plans = devices.map((device) =>
      this.buildDevicePlan(
        device,
        keyTelematicsClientId,
        ktDeviceSelections,
        ktDeviceTypeOverrides,
        headers,
        simCardsUrl,
      ),
    );
    const devicePlans$: Observable<DeviceSyncPlan[]> =
      plans.length === 0 ? of([]) : forkJoin<DeviceSyncPlan[]>(plans);

    return forkJoin([assetCheck$, devicePlans$]).pipe(
      map(([assetFound, devicePlans]): SyncPlan => {
        const entityChecks: EntityCheckItem[] = [
          {
            type: 'asset',
            label: asset.name ?? '',
            existingId: assetFound?.id ?? null,
          },
        ];

        for (const dp of devicePlans) {
          entityChecks.push({
            type: 'device',
            label: dp.device.name ?? dp.device.id,
            existingId: dp.existingKtDeviceId,
            conflict: dp.deviceConflict,
            conflictOwnerName: dp.deviceConflictOwnerName,
          });
          if (dp.simCard) {
            entityChecks.push({
              type: 'simCard',
              label: dp.simCard.name ?? dp.simCard.id,
              existingId: dp.existingKtSimCardId,
            });
          }
        }

        return { asset, devicePlans, entityChecks };
      }),
    );
  }

  // ── Sync ──────────────────────────────────────────────────────────────────

  syncAsset(
    plan: SyncPlan,
    keyTelematicsClientId: string,
    resolvedIds: ResolvedIds,
    ktDeviceTypeOverrides: KtDeviceTypeOverrides,
    ktGroups: { id: string; name: string }[],
    ktCategories: { id: string; name: string }[],
  ): Observable<KeyTelematicsSyncResult> {
    if (!this.loginState) {
      return of({
        success: false,
        message: 'Not authenticated with Key Telematics.',
      });
    }
    return this.executeSync(
      plan,
      keyTelematicsClientId,
      resolvedIds,
      ktDeviceTypeOverrides,
      ktGroups,
      ktCategories,
    );
  }

  // ── Private: execute sync ─────────────────────────────────────────────────

  private executeSync(
    plan: SyncPlan,
    keyTelematicsClientId: string,
    resolvedIds: ResolvedIds,
    ktDeviceTypeOverrides: KtDeviceTypeOverrides,
    ktGroups: { id: string; name: string }[],
    ktCategories: { id: string; name: string }[],
  ): Observable<KeyTelematicsSyncResult> {
    const { asset, devicePlans, entityChecks } = plan;
    const headers = this.buildHeaders();
    const assetsUrl = `${this.keyTelematicsApiUrl}/entities/assets`;

    const assetExistingId =
      entityChecks.find((c) => c.type === 'asset')?.existingId ?? null;

    const ktAssetId$: Observable<string> = isDefined(assetExistingId)
      ? this.put(
          `${assetsUrl}/${assetExistingId}`,
          this.buildAssetUpdateBody(asset, resolvedIds, ktGroups, ktCategories),
          headers,
        ).pipe(map((r) => (r.ok ? assetExistingId : '')))
      : this.http
          .post<{
            id?: string;
          }>(
            assetsUrl,
            this.buildAssetCreateBody(
              asset,
              keyTelematicsClientId,
              resolvedIds,
              ktGroups,
              ktCategories,
            ),
            { headers },
          )
          .pipe(
            map((res) => res.id ?? ''),
            catchError((err) => {
              if (err?.status === 401) this.clearToken();
              console.error(
                '[KeyTelematicsSyncService] Asset POST failed:',
                err,
              );
              return of('');
            }),
            delay(1100),
          );

    return ktAssetId$.pipe(
      switchMap((ktAssetId) => {
        if (!ktAssetId) {
          return of({
            success: false,
            message: 'Failed to create/update asset in Key Telematics.',
          });
        }

        if (devicePlans.length === 0) {
          return of({
            success: true,
            message: '1 asset synced to Key Telematics successfully.',
          });
        }

        return from(devicePlans).pipe(
          concatMap((dp) =>
            this.syncDevice(
              dp,
              ktAssetId,
              asset.name ?? '',
              keyTelematicsClientId,
              ktDeviceTypeOverrides,
              headers,
            ),
          ),
          toArray(),
          map((results) => {
            const failed = results.filter((r) => !r.ok).length;
            if (failed > 0) {
              return {
                success: false,
                message: `1 asset synced but ${failed} device${failed === 1 ? '' : 's'} failed to sync.`,
              };
            }
            const deviceCount = results.length;
            const simCount = results.filter((r) => r.simCardSynced).length;
            const parts: string[] = [
              `${deviceCount} device${deviceCount === 1 ? '' : 's'}`,
            ];
            if (simCount > 0) {
              parts.push(`${simCount} SIM card${simCount === 1 ? '' : 's'}`);
            }
            return {
              success: true,
              message: `1 asset and ${parts.join(' and ')} synced to Key Telematics.`,
            };
          }),
        );
      }),
      catchError(() => {
        return of({
          success: false,
          message: 'An unexpected error occurred during sync.',
        });
      }),
    );
  }

  private buildDevicePlan(
    device: DeviceResponse,
    keyTelematicsClientId: string,
    ktDeviceSelections: KtDeviceSelections,
    ktDeviceTypeOverrides: KtDeviceTypeOverrides,
    headers: HttpHeaders,
    simCardsUrl: string,
  ): Observable<DeviceSyncPlan> {
    const manualKtDeviceId = ktDeviceSelections.get(device.id) ?? null;

    // Prefer the user's explicit KT device selection; otherwise do a
    // global (non-client-scoped) lookup by type + name so we detect devices
    // that already exist under a different client and update rather than
    // try to create (which KT would reject as a duplicate).
    const ktTypeId = ktDeviceTypeOverrides.get(device.id);
    // Global KT lookup: { id, conflict } — conflict is true when the device
    // exists in KT but belongs to a different client than the sync target.
    const ktDeviceLookup$: Observable<{
      id: string | null;
      conflict: boolean;
      ownerName: string;
    }> = isDefined(manualKtDeviceId)
      ? of({ id: manualKtDeviceId, conflict: false, ownerName: '' })
      : isDefined(ktTypeId) && isDefined(device.name)
        ? this.http
            .get<{
              id?: string;
              owner?: { id?: string; name?: string };
            }>(
              `${this.keyTelematicsApiUrl}/entities/devices/name/${encodeURIComponent(ktTypeId)}/${encodeURIComponent(device.name)}`,
              { headers },
            )
            .pipe(
              map((d) => {
                if (!isDefined(d?.id))
                  return { id: null, conflict: false, ownerName: '' };
                const ownerId = d.owner?.id ?? '';
                const conflict =
                  ownerId.length > 0 && ownerId !== keyTelematicsClientId;
                return {
                  id: conflict ? null : d.id,
                  conflict,
                  ownerName: d.owner?.name ?? '',
                };
              }),
              catchError(() =>
                of({ id: null, conflict: false, ownerName: '' }),
              ),
            )
        : of({ id: null, conflict: false, ownerName: '' });

    const simCardId = device.simcard?.id;

    return ktDeviceLookup$.pipe(
      switchMap(
        ({ id: existingKtDeviceId, conflict: deviceConflict, ownerName }) => {
          if (deviceConflict) {
            return of<DeviceSyncPlan>({
              device,
              simCard: null,
              existingKtDeviceId: null,
              existingKtSimCardId: null,
              deviceConflict: true,
              deviceConflictOwnerName: ownerName,
            });
          }
          if (!isDefined(simCardId)) {
            return of<DeviceSyncPlan>({
              device,
              simCard: null,
              existingKtDeviceId,
              existingKtSimCardId: null,
            });
          }
          return this.buildDevicePlanWithSimCard(
            device,
            existingKtDeviceId,
            simCardId,
            keyTelematicsClientId,
            headers,
            simCardsUrl,
          );
        },
      ),
    );
  }

  private buildDevicePlanWithSimCard(
    device: DeviceResponse,
    existingKtDeviceId: string | null,
    simCardId: string,
    keyTelematicsClientId: string,
    headers: HttpHeaders,
    simCardsUrl: string,
  ): Observable<DeviceSyncPlan> {
    return this.entitiesService
      .getSimCard(simCardId)
      .pipe(catchError(() => of(null)))
      .pipe(
        switchMap((simCard) => {
          if (!simCard) {
            return of<DeviceSyncPlan>({
              device,
              simCard: null,
              existingKtDeviceId,
              existingKtSimCardId: null,
            });
          }
          return this.findByName<{ id?: string }>(
            simCardsUrl,
            simCard.name ?? '',
            keyTelematicsClientId,
            headers,
          ).pipe(
            map(
              (ktSimCard): DeviceSyncPlan => ({
                device,
                simCard,
                existingKtDeviceId,
                existingKtSimCardId: ktSimCard?.id ?? null,
              }),
            ),
          );
        }),
      );
  }

  private syncDevice(
    dp: DeviceSyncPlan,
    ktAssetId: string,
    ktAssetName: string,
    ownerId: string,
    ktDeviceTypeOverrides: KtDeviceTypeOverrides,
    headers: HttpHeaders,
  ): Observable<{ ok: boolean; simCardSynced: boolean }> {
    const devicesUrl = `${this.keyTelematicsApiUrl}/entities/devices`;
    const ktDeviceTypeId = ktDeviceTypeOverrides.get(dp.device.id);

    // Sync SIM card first (if any) to know its KT ID for inclusion in device body
    const ktSimCardId$: Observable<string | null> = dp.simCard
      ? this.syncSimCard(dp.simCard, dp.existingKtSimCardId, ownerId, headers)
      : of(null);

    return ktSimCardId$.pipe(
      switchMap((ktSimCardId) => {
        const simCardSynced = isDefined(ktSimCardId);
        const assetLink = { id: ktAssetId, name: ktAssetName };
        const simcardLink = simCardSynced
          ? { simcard: { id: ktSimCardId, name: dp.simCard?.name ?? '' } }
          : {};

        if (isDefined(dp.existingKtDeviceId)) {
          const updateBody = {
            ...this.buildDeviceUpdateBody(dp.device, ktDeviceTypeId),
            asset: assetLink,
            ...simcardLink,
          };

          return this.put(
            `${devicesUrl}/${dp.existingKtDeviceId}`,
            updateBody,
            headers,
          ).pipe(map((r) => ({ ...r, simCardSynced })));
        }

        const createBody: DeviceCreateRequest = {
          ...this.buildDeviceCreateBody(dp.device, ownerId, ktDeviceTypeId),
          asset: assetLink,
          ...simcardLink,
        };

        return this.http
          .post<{ id?: string }>(devicesUrl, createBody, { headers })
          .pipe(
            map(() => ({ ok: true, simCardSynced })),
            catchError((err) => {
              if (err?.status === 401) this.clearToken();
              console.error(
                '[KeyTelematicsSyncService] Device POST failed:',
                err,
              );
              return of({ ok: false, simCardSynced: false });
            }),
            delay(1100),
          );
      }),
      catchError(() => {
        return of({ ok: false, simCardSynced: false });
      }),
    );
  }

  private syncSimCard(
    simCard: SimCardResponse,
    existingKtSimCardId: string | null,
    ownerId: string,
    headers: HttpHeaders,
  ): Observable<string | null> {
    const simCardsUrl = `${this.keyTelematicsApiUrl}/entities/simcards`;

    if (isDefined(existingKtSimCardId)) {
      return this.put(
        `${simCardsUrl}/${existingKtSimCardId}`,
        this.buildSimCardUpdateBody(simCard),
        headers,
      ).pipe(map((r) => (r.ok ? existingKtSimCardId : null)));
    }

    return this.http
      .post<{
        id?: string;
      }>(simCardsUrl, this.buildSimCardCreateBody(simCard, ownerId), {
        headers,
      })
      .pipe(
        map((res) => res.id ?? null),
        catchError((err) => {
          if (err?.status === 401) this.clearToken();

          return of(null);
        }),
        delay(1100),
      );
  }

  // ── Private: body builders ────────────────────────────────────────────────

  private buildAssetCreateBody(
    asset: AssetResponse,
    ownerId: string,
    resolvedIds: ResolvedIds,
    ktGroups: { id: string; name: string }[],
    ktCategories: { id: string; name: string }[],
  ): AssetCreateRequest {
    return {
      ownerId,
      name: asset.name ?? '',
      assetType: this.resolveIdName('assetType', asset.assetType, resolvedIds),
      costCentre: this.resolveIdName(
        'costCentre',
        asset.costCentre,
        resolvedIds,
      ),
      groups: ktGroups,
      categories: ktCategories,
      state: asset.state,
      fields: asset.fields,
      tags: asset.tags,
      color: asset.color,
    };
  }

  private buildAssetUpdateBody(
    asset: AssetResponse,
    resolvedIds: ResolvedIds,
    ktGroups: { id: string; name: string }[],
    ktCategories: { id: string; name: string }[],
  ): AssetUpdateRequest {
    return {
      name: asset.name,
      assetType: this.resolveIdName('assetType', asset.assetType, resolvedIds),
      costCentre: this.resolveIdName(
        'costCentre',
        asset.costCentre,
        resolvedIds,
      ),
      groups: ktGroups,
      categories: ktCategories,
      state: asset.state,
      fields: asset.fields,
      tags: asset.tags,
      color: asset.color,
    };
  }

  private buildDeviceCreateBody(
    device: DeviceResponse,
    ownerId: string,
    ktDeviceTypeId: string | undefined,
  ): DeviceCreateRequest {
    return {
      ownerId,
      name: device.name ?? '',
      ...(isDefined(ktDeviceTypeId) && {
        deviceType: { id: ktDeviceTypeId, name: device.deviceType?.name ?? '' },
      }),
      state: device.state,
      fields: device.fields,
    } as DeviceCreateRequest;
  }

  private buildDeviceUpdateBody(
    device: DeviceResponse,
    ktDeviceTypeId: string | undefined,
  ): DeviceUpdateRequest {
    return {
      name: device.name,
      deviceType: isDefined(ktDeviceTypeId)
        ? { id: ktDeviceTypeId, name: device.deviceType?.name ?? '' }
        : undefined,
      state: device.state,
      fields: device.fields,
    };
  }

  private buildSimCardCreateBody(
    simCard: SimCardResponse,
    ownerId: string,
  ): SimCardCreateRequest {
    return {
      ownerId,
      name: simCard.name ?? '',
      networkName: simCard.networkName ?? '',
      number: simCard.number ?? '',
      description: simCard.description ?? '',
      state: simCard.state,
      fields: simCard.fields,
    };
  }

  private buildSimCardUpdateBody(
    simCard: SimCardResponse,
  ): SimCardUpdateRequest {
    return {
      name: simCard.name,
      networkName: simCard.networkName,
      number: simCard.number,
      description: simCard.description,
      state: simCard.state,
      fields: simCard.fields,
    };
  }

  private resolveIdName(
    type: 'assetType' | 'costCentre' | 'group' | 'category',
    source: { id?: string; name?: string | null } | null | undefined,
    resolvedIds: ResolvedIds,
  ): { id: string; name?: string | null } {
    const name = source?.name ?? null;
    const resolvedId = isDefined(name)
      ? resolvedIds.get(`${type}:${name}`)
      : undefined;
    const id = resolvedId ?? source?.id ?? '';
    if (!id)
      console.warn(
        `[KeyTelematicsSyncService] resolveIdName: no id resolved for ${type}:${name}`,
      );
    return { id, name };
  }

  // ── Private: search helper ───────────────────────────────────────────────

  private searchEntities<T>(
    endpoint: string,
    term: string,
    clientId: string,
  ): Observable<T[]> {
    if (!this.loginState) return of([]);
    return this.http
      .get<{ items: T[] }>(`${this.keyTelematicsApiUrl}/${endpoint}`, {
        headers: this.buildHeaders(),
        params: this.buildSearchParams(term, clientId),
      })
      .pipe(
        map((res) => res.items ?? []),
        catchError((err) => {
          if (err?.status === 401) this.clearToken();
          return of([]);
        }),
      );
  }

  // ── Private: HTTP helpers ─────────────────────────────────────────────────

  private findByName<T extends { id?: string; name?: string }>(
    url: string,
    name: string,
    owner: string,
    headers: HttpHeaders,
  ): Observable<T | null> {
    const params = new HttpParams()
      .set('owner', owner)
      .set('limit', '1')
      .set('filter', `name=${this.ktEncode(name)}`);

    return this.http.get<{ items: T[] }>(url, { headers, params }).pipe(
      map((res) => res.items?.find((i) => i.name === name) ?? null),
      catchError((err) => {
        if (err?.status === 401) this.clearToken();
        return of(null);
      }),
    );
  }

  private buildSearchParams(term: string, owner: string): HttpParams {
    const encoded = this.ktEncode(term);
    const base = new HttpParams()
      .set('owner', owner)
      .set('limit', '20')
      .set('sort', 'name');
    return encoded ? base.set('filter', `name=*${encoded}*`) : base;
  }

  // KT filter values use $XX hex encoding (like URL encoding but with $ instead of %).
  // Angular's HttpUrlEncodingCodec keeps $ unescaped per RFC 3986, so it reaches the
  // server as-is and KT's filter parser decodes it correctly.
  private ktEncode(value: string): string {
    return encodeURIComponent(value.trim()).replaceAll('%', '$');
  }

  private put(
    url: string,
    body: object,
    headers: HttpHeaders,
  ): Observable<{ ok: boolean }> {
    return this.http.put(url, body, { headers }).pipe(
      map(() => ({ ok: true })),
      catchError((err) => {
        if (err?.status === 401) this.clearToken();

        return of({ ok: false });
      }),
      delay(1100),
    );
  }

  private buildHeaders(): HttpHeaders {
    return new HttpHeaders({
      'x-access-token': this.loginState?.accessToken ?? '',
      'Content-Type': 'application/json',
    });
  }
}
