import {
  AfterViewInit,
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  Component,
  DestroyRef,
  inject,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed, toSignal } from '@angular/core/rxjs-interop';
import {
  FormGroup,
  NonNullableFormBuilder,
  ReactiveFormsModule,
  Validators,
} from '@angular/forms';
import { CommonModule } from '@angular/common';
import {
  Subject,
  debounceTime,
  forkJoin,
  switchMap,
  of,
  catchError,
  map,
  firstValueFrom,
  Observable,
} from 'rxjs';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { PasswordModule } from 'primeng/password';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { MessageModule } from 'primeng/message';
import { TagModule } from 'primeng/tag';
import { DynamicDialogRef } from 'primeng/dynamicdialog';

import {
  AssetResponse,
  AuthUserResponse,
  ClientListItem,
  DeviceResponse,
} from '../../../../../api';
import {
  EntityCheckItem,
  KeyTelematicsSyncResult,
  KeyTelematicsSyncService,
  KtDeviceSelections,
  KtDeviceTypeOverrides,
  ResolvedIds,
  SyncPlan,
} from '../../../services/key-sync.service';
import { EntityDetailsStateService } from '../../../services/entity/entity-details.state.service';
import { WizardComponent } from '../../../../../shared/components/wizard/wizard.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { SEARCH_DEBOUNCE_TIME } from '../../../../../core/models';
import {
  createAutocompleteField,
  FormFieldConfig,
  Step,
} from '../../../../../shared/models';
import { faLock, faSync, faLink } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { TranslatePipe } from '@ngx-translate/core';
import { isDefined } from '../../../../../shared/utils';

type DialogStage = 'wizard' | 'confirm' | 'syncing' | 'result';
type LoginStage = 'credentials' | 'account-select' | 'connected';
type DepType = 'assetType' | 'costCentre' | 'group' | 'category';
type KtMatch = { id: string; name: string } | null;

interface KtPreFetch {
  assetType: KtMatch;
  costCentre: KtMatch;
  groups: KtMatch[];
  categories: KtMatch[];
  deviceMatches: [KtMatch, KtMatch][];
}

interface DepFieldMeta {
  fieldKey: string;
  depType: DepType;
  sourceName: string;
}

interface DeviceSelectionMeta {
  fieldKey: string;
  cvDeviceId: string;
}

interface DeviceTypeOverrideMeta {
  fieldKey: string;
  cvDeviceId: string;
}

@Component({
  selector: 'app-keys-sync-dialog',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    InputTextModule,
    PasswordModule,
    ProgressSpinnerModule,
    MessageModule,
    TagModule,
    WizardComponent,
    DynamicFormComponent,
    FontAwesomeModule,
    TranslatePipe,
  ],
  templateUrl: './key-telematics-sync-dialog.component.html',
  styleUrl: './key-telematics-sync-dialog.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class KeyTelematicsSyncDialogComponent implements AfterViewInit {
  private readonly fb = inject(NonNullableFormBuilder);
  private readonly dialogRef = inject(DynamicDialogRef);
  private readonly keySyncService = inject(KeyTelematicsSyncService);
  private readonly entityStateService = inject(EntityDetailsStateService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly cdr = inject(ChangeDetectorRef);

  // ── Stage ────────────────────────────────────────────────────────────────
  readonly stage = signal<DialogStage>('wizard');
  readonly syncResult = signal<KeyTelematicsSyncResult | null>(null);
  readonly syncPlan = signal<SyncPlan | null>(null);
  readonly isChecking = signal(false);

  // ── Step 1: Credentials ──────────────────────────────────────────────────
  readonly credForm = this.fb.group({
    username: ['', Validators.required],
    password: ['', Validators.required],
  });
  readonly isLoggingIn = signal(false);
  readonly isSelectingAccount = signal(false);
  readonly loginError = signal<string | null>(null);
  readonly loginStage = signal<LoginStage>('credentials');
  readonly ktAccounts = signal<AuthUserResponse[]>([]);

  private readonly credFormValid = toSignal(
    this.credForm.statusChanges.pipe(map(() => this.credForm.valid)),
    { initialValue: false },
  );

  // ── Step 2: Client Selection ─────────────────────────────────────────────
  readonly clientSearchResults = signal<ClientListItem[] | undefined>(
    undefined,
  );
  readonly selectedClient = signal<ClientListItem | null>(null);
  clientFormFields: FormFieldConfig[] = [];

  private readonly clientSearchSubject = new Subject<string>();

  // ── Step 3: Dependency Mapping + Device Selection ────────────────────────
  readonly assetDevices = signal<DeviceResponse[]>([]);
  depFormFields: FormFieldConfig[] = [];
  private depFieldMeta: DepFieldMeta[] = [];
  private deviceSelectionMeta: DeviceSelectionMeta[] = [];
  private deviceTypeOverrideMeta: DeviceTypeOverrideMeta[] = [];
  private resolvedIds: ResolvedIds = new Map();
  private ktGroups: { id: string; name: string }[] = [];
  private ktCategories: { id: string; name: string }[] = [];
  private ktDeviceSelections: KtDeviceSelections = new Map();
  private ktDeviceTypeOverrides: KtDeviceTypeOverrides = new Map();

  private readonly assetTypeSearch$ = new Subject<string>();
  private readonly costCentreSearch$ = new Subject<string>();
  private readonly groupSearch$ = new Subject<string>();
  private readonly categorySearch$ = new Subject<string>();
  private readonly ktDeviceSearch$ = new Subject<string>();
  private readonly deviceTypeSearch$ = new Subject<string>();

  // ── Wizard ───────────────────────────────────────────────────────────────
  readonly steps = signal<Step[]>([]);

  @ViewChild('loginContent') private readonly loginContent!: TemplateRef<{
    $implicit: Step;
  }>;
  @ViewChild('clientContent') private readonly clientContent!: TemplateRef<{
    $implicit: Step;
  }>;
  @ViewChild('depContent') private readonly depContent!: TemplateRef<{
    $implicit: Step;
  }>;

  faSync = faSync;
  faLock = faLock;
  faLink = faLink;

  constructor() {
    const accounts = this.keySyncService.getAccounts();
    if (this.keySyncService.isAuthenticated) {
      this.loginStage.set('connected');
      this.ktAccounts.set(accounts);
    } else if (accounts.length > 0) {
      // Token stored but no account selected yet (multiple accounts, page refreshed)
      this.loginStage.set('account-select');
      this.ktAccounts.set(accounts);
    }
    this.setupClientSearch();
    this.setupDepSearches();
  }

  get selectedAccountName(): string {
    return this.keySyncService.getSelectedAccount()?.owner.name ?? '';
  }

  ngAfterViewInit(): void {
    this.buildSteps();
    this.setupStepReactivity();
  }

  // ── Setup ─────────────────────────────────────────────────────────────────

  private buildSteps(): void {
    this.steps.set([
      {
        value: 1,
        header: 'Login',
        content: this.loginContent,
        disableNext: this.loginStage() !== 'connected' && !this.credFormValid(),
        validate: (): Promise<boolean> | boolean => {
          if (this.loginStage() === 'connected') return this.verifyAndProceed();
          if (this.loginStage() === 'credentials') return this.performLogin();
          return false; // 'account-select': Next is disabled, this branch won't run
        },
      },
      {
        value: 2,
        header: 'Select Client',
        content: this.clientContent,
        disableNext: !this.selectedClient(),
        validate: () => this.loadDevicesAndBuildDepForm(),
      },
      {
        value: 3,
        header: 'Map Dependencies',
        content: this.depContent,
        disableNext: true,
      },
    ]);

    this.clientFormFields = [
      createAutocompleteField(
        'client',
        'Key Telematics Client',
        null,
        this.clientSearchResults(),
        (term) => this.onClientSearch(term),
        {
          props: {
            field: 'name',
            appendTo: 'body',
            placeholder: 'Search for a client in Key Telematics',
            completeOnFocus: false,
            typeahead: true,
            showEmptyMessage: true,
            emptyMessage: 'No clients found',
            forceSelection: true,
          },
        },
      ),
    ];
  }

  private setupStepReactivity(): void {
    this.credForm.statusChanges
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(() => {
        this.steps.update((current) =>
          current.map((s) =>
            s.value === 1
              ? {
                  ...s,
                  disableNext:
                    this.loginStage() !== 'connected' &&
                    (!this.credForm.valid || this.isLoggingIn()),
                }
              : s,
          ),
        );
      });
  }

  private setupClientSearch(): void {
    this.clientSearchSubject
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        takeUntilDestroyed(this.destroyRef),
        switchMap((term) =>
          this.keySyncService
            .searchClients(term)
            .pipe(catchError(() => of([]))),
        ),
      )
      .subscribe((results) => {
        this.clientSearchResults.set(results);
        const field = this.clientFormFields.find((f) => f.key === 'client');
        if (field?.props) {
          field.props = { ...field.props, suggestions: results };
        }
        this.cdr.detectChanges();
      });
  }

  private setupDepSearches(): void {
    const depConfigs: {
      subject: Subject<string>;
      search: (
        term: string,
        clientId: string,
      ) => Observable<{ id: string; name: string }[]>;
      depType: DepType;
    }[] = [
      {
        subject: this.assetTypeSearch$,
        search: (t, c) => this.keySyncService.searchAssetTypes(t, c),
        depType: 'assetType',
      },
      {
        subject: this.costCentreSearch$,
        search: (t, c) => this.keySyncService.searchCostCentres(t, c),
        depType: 'costCentre',
      },
      {
        subject: this.groupSearch$,
        search: (t, c) => this.keySyncService.searchGroups(t, c),
        depType: 'group',
      },
      {
        subject: this.categorySearch$,
        search: (t, c) => this.keySyncService.searchCategories(t, c),
        depType: 'category',
      },
    ];

    for (const config of depConfigs) {
      config.subject
        .pipe(
          debounceTime(SEARCH_DEBOUNCE_TIME),
          takeUntilDestroyed(this.destroyRef),
          switchMap((term) =>
            config
              .search(term, this.selectedClient()?.id ?? '')
              .pipe(catchError(() => of([]))),
          ),
        )
        .subscribe((results) => {
          this.updateDepFieldSuggestions(config.depType, results);
          this.cdr.detectChanges();
        });
    }

    // KT device search — updates all device selection fields
    this.ktDeviceSearch$
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        takeUntilDestroyed(this.destroyRef),
        switchMap((term) =>
          this.keySyncService
            .searchKtDevices(term, this.selectedClient()?.id ?? '')
            .pipe(catchError(() => of([]))),
        ),
      )
      .subscribe((results) => {
        this.updateDeviceFieldSuggestions(results);
        this.cdr.detectChanges();
      });

    // Device type search — updates all device type override fields
    this.deviceTypeSearch$
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        takeUntilDestroyed(this.destroyRef),
        switchMap((term) =>
          this.keySyncService
            .searchDeviceTypes(term, this.selectedClient()?.id ?? '')
            .pipe(catchError(() => of([]))),
        ),
      )
      .subscribe((results) => {
        this.updateDeviceTypeFieldSuggestions(results);
        this.cdr.detectChanges();
      });
  }

  // ── Actions ───────────────────────────────────────────────────────────────

  private async performLogin(): Promise<boolean> {
    const { username, password } = this.credForm.getRawValue();
    this.isLoggingIn.set(true);
    this.loginError.set(null);
    this.steps.update((s) =>
      s.map((step) =>
        step.value === 1 ? { ...step, disableNext: true } : step,
      ),
    );

    try {
      await firstValueFrom(this.keySyncService.login(username, password));
      this.isLoggingIn.set(false);
      const accounts = this.keySyncService.getAccounts();
      this.ktAccounts.set(accounts);

      if (this.keySyncService.isAuthenticated) {
        // Single account — auto-selected, proceed
        this.loginStage.set('connected');
        this.steps.update((s) =>
          s.map((step) =>
            step.value === 1 ? { ...step, disableNext: false } : step,
          ),
        );
        return true;
      } else {
        // Multiple accounts — show picker; user must select before Next
        this.loginStage.set('account-select');
        this.steps.update((s) =>
          s.map((step) =>
            step.value === 1 ? { ...step, disableNext: true } : step,
          ),
        );
        this.cdr.detectChanges();
        return false;
      }
    } catch (err: unknown) {
      this.isLoggingIn.set(false);
      const status = (err as { status?: number })?.status;
      this.loginError.set(
        status === 401
          ? 'Invalid credentials. Please check your Key Telematics username and password.'
          : 'Login failed. Please try again.',
      );
      this.steps.update((s) =>
        s.map((step) =>
          step.value === 1
            ? { ...step, disableNext: !this.credForm.valid }
            : step,
        ),
      );
      return false;
    }
  }

  private async verifyAndProceed(): Promise<boolean> {
    const valid: boolean = await firstValueFrom(
      this.keySyncService.verifySession(),
    );
    if (!valid) {
      this.loginStage.set('credentials');
      this.loginError.set('Your session has expired. Please sign in again.');
      this.steps.update((s) =>
        s.map((step) =>
          step.value === 1
            ? { ...step, disableNext: !this.credForm.valid }
            : step,
        ),
      );
    }
    return valid;
  }

  private async loadDevicesAndBuildDepForm(): Promise<boolean> {
    const client = this.selectedClient();
    const asset =
      this.entityStateService.selectedItem() as AssetResponse | null;
    if (!client || !asset) return false;

    let devices: DeviceResponse[] = [];
    try {
      devices = await firstValueFrom(this.keySyncService.fetchDevices(asset));
      this.assetDevices.set(devices);
      const ktPreFetch = await this.prefetchKtMatches(
        asset,
        devices,
        client.id,
      );
      this.buildDepFormFields(asset, devices, ktPreFetch);
    } catch {
      this.buildDepFormFields(
        asset,
        devices,
        KeyTelematicsSyncDialogComponent.EMPTY_KT_PRE_FETCH,
      );
    }

    const hasRequiredFields =
      this.depFieldMeta.length > 0 || this.deviceTypeOverrideMeta.length > 0;
    this.steps.update((s) =>
      s.map((step) =>
        step.value === 3 ? { ...step, disableNext: hasRequiredFields } : step,
      ),
    );
    this.cdr.detectChanges();
    return true;
  }

  private async prefetchKtMatches(
    asset: AssetResponse,
    devices: DeviceResponse[],
    clientId: string,
  ): Promise<KtPreFetch> {
    const exact = (
      obs$: Observable<KtMatch[]>,
      name: string,
    ): Observable<KtMatch> =>
      obs$.pipe(
        map((r) => r.find((x) => x !== null && x.name === name) ?? null),
        catchError(() => of(null)),
      );

    const groups = (asset.groups ?? []).filter(
      (g): g is typeof g & { name: string } => isDefined(g.name),
    );
    const categories = (asset.categories ?? []).filter(
      (c): c is typeof c & { name: string } => isDefined(c.name),
    );
    const assetTypeName = asset.assetType?.name;
    const costCentreName = asset.costCentre?.name;

    const [
      assetType,
      costCentre,
      groupMatches,
      categoryMatches,
      deviceMatches,
    ] = await Promise.all([
      isDefined(assetTypeName)
        ? firstValueFrom(
            exact(
              this.keySyncService.searchAssetTypes(assetTypeName, clientId),
              assetTypeName,
            ),
          )
        : Promise.resolve(null),
      isDefined(costCentreName)
        ? firstValueFrom(
            exact(
              this.keySyncService.searchCostCentres(costCentreName, clientId),
              costCentreName,
            ),
          )
        : Promise.resolve(null),
      groups.length > 0
        ? firstValueFrom(
            forkJoin(
              groups.map((g) =>
                exact(
                  this.keySyncService.searchGroups(g.name, clientId),
                  g.name,
                ),
              ),
            ),
          )
        : Promise.resolve([] as KtMatch[]),
      categories.length > 0
        ? firstValueFrom(
            forkJoin(
              categories.map((c) =>
                exact(
                  this.keySyncService.searchCategories(c.name, clientId),
                  c.name,
                ),
              ),
            ),
          )
        : Promise.resolve([] as KtMatch[]),
      devices.length > 0
        ? firstValueFrom(
            forkJoin(
              devices.map((d) =>
                forkJoin([
                  isDefined(d.name)
                    ? exact(
                        this.keySyncService.searchKtDevices(d.name, clientId),
                        d.name,
                      )
                    : of(null),
                  isDefined(d.deviceType?.name)
                    ? exact(
                        this.keySyncService.searchDeviceTypes(
                          d.deviceType.name,
                          clientId,
                        ),
                        d.deviceType.name,
                      )
                    : of(null),
                ]),
              ),
            ),
          )
        : Promise.resolve([] as [KtMatch, KtMatch][]),
    ]);

    return {
      assetType,
      costCentre,
      groups: groupMatches,
      categories: categoryMatches,
      deviceMatches: deviceMatches,
    };
  }

  private static readonly EMPTY_KT_PRE_FETCH: KtPreFetch = {
    assetType: null,
    costCentre: null,
    groups: [],
    categories: [],
    deviceMatches: [],
  };

  private buildDepFormFields(
    asset: AssetResponse,
    devices: DeviceResponse[],
    ktPreFetch: KtPreFetch = KeyTelematicsSyncDialogComponent.EMPTY_KT_PRE_FETCH,
  ): void {
    const depMeta: DepFieldMeta[] = [];
    const fields: FormFieldConfig[] = [];

    // Asset type
    const assetTypeName = asset.assetType?.name;
    if (isDefined(assetTypeName)) {
      const preMatch = ktPreFetch.assetType;
      depMeta.push({
        fieldKey: 'assetType',
        depType: 'assetType',
        sourceName: assetTypeName,
      });
      fields.push(
        createAutocompleteField(
          'assetType',
          'Asset Type',
          preMatch,
          preMatch ? [preMatch] : [],
          (term) => this.onDepSearch('assetType', term),
          {
            hint: `CypherView: "${assetTypeName}"`,
            props: this.acFieldProps('Search asset types…'),
          },
        ),
      );
    }

    // Cost centre
    const costCentreName = asset.costCentre?.name;
    if (isDefined(costCentreName)) {
      const preMatch = ktPreFetch.costCentre;
      depMeta.push({
        fieldKey: 'costCentre',
        depType: 'costCentre',
        sourceName: costCentreName,
      });
      fields.push(
        createAutocompleteField(
          'costCentre',
          'Cost Centre',
          preMatch,
          preMatch ? [preMatch] : [],
          (term) => this.onDepSearch('costCentre', term),
          {
            hint: `CypherView: "${costCentreName}"`,
            props: this.acFieldProps('Search cost centres…'),
          },
        ),
      );
    }

    // Groups — single multi-select field for all groups
    const groupNames = (asset.groups ?? [])
      .map((g) => g.name)
      .filter((n): n is string => isDefined(n));
    if (groupNames.length > 0) {
      const preGroups = ktPreFetch.groups.filter(
        (g): g is NonNullable<typeof g> => g !== null,
      );
      fields.push(
        createAutocompleteField(
          'groups',
          'Groups',
          preGroups,
          preGroups,
          (term) => this.onDepSearch('group', term),
          {
            hint: `CypherView: ${groupNames.map((n) => `"${n}"`).join(', ')}`,
            props: { ...this.acFieldProps('Search groups…'), multiple: true },
          },
        ),
      );
    }

    // Categories — single multi-select field for all categories
    const categoryNames = (asset.categories ?? [])
      .map((c) => c.name)
      .filter((n): n is string => isDefined(n));
    if (categoryNames.length > 0) {
      const preCategories = ktPreFetch.categories.filter(
        (c): c is NonNullable<typeof c> => c !== null,
      );
      fields.push(
        createAutocompleteField(
          'categories',
          'Categories',
          preCategories,
          preCategories,
          (term) => this.onDepSearch('category', term),
          {
            hint: `CypherView: ${categoryNames.map((n) => `"${n}"`).join(', ')}`,
            props: {
              ...this.acFieldProps('Search categories…'),
              multiple: true,
            },
          },
        ),
      );
    }

    const {
      deviceMeta,
      deviceTypeOverrideMeta,
      fields: deviceFields,
    } = this.buildDeviceFormFields(devices, ktPreFetch);

    this.depFieldMeta = depMeta;
    this.deviceSelectionMeta = deviceMeta;
    this.deviceTypeOverrideMeta = deviceTypeOverrideMeta;
    this.depFormFields = [...fields, ...deviceFields];
  }

  private buildDeviceFormFields(
    devices: DeviceResponse[],
    ktPreFetch: KtPreFetch,
  ): {
    deviceMeta: DeviceSelectionMeta[];
    deviceTypeOverrideMeta: DeviceTypeOverrideMeta[];
    fields: FormFieldConfig[];
  } {
    const deviceMeta: DeviceSelectionMeta[] = [];
    const deviceTypeOverrideMeta: DeviceTypeOverrideMeta[] = [];
    const fields: FormFieldConfig[] = [];

    for (const [i, device] of devices.entries()) {
      const deviceId = device.id;
      if (!isDefined(deviceId)) continue;
      const [ktDeviceMatch, ktDeviceTypeMatch] = ktPreFetch.deviceMatches[
        i
      ] ?? [null, null];
      const deviceTypeName = device.deviceType?.name ?? null;
      const deviceLabel = device.name ?? deviceId;

      const deviceFieldKey = `ktDevice_${deviceId}`;
      deviceMeta.push({ fieldKey: deviceFieldKey, cvDeviceId: deviceId });
      fields.push(
        createAutocompleteField(
          deviceFieldKey,
          `KT Device: ${deviceLabel}`,
          ktDeviceMatch,
          ktDeviceMatch ? [ktDeviceMatch] : [],
          (term) => this.onKtDeviceSearch(term),
          {
            hint: `CypherView: "${deviceLabel}" — leave empty to create a new device in KT`,
            props: this.acFieldProps('Search devices in Key Telematics…'),
          },
        ),
      );

      const typeFieldKey = `deviceType_${deviceId}`;
      deviceTypeOverrideMeta.push({
        fieldKey: typeFieldKey,
        cvDeviceId: deviceId,
      });
      fields.push(
        createAutocompleteField(
          typeFieldKey,
          `Device Type: ${deviceLabel}`,
          ktDeviceTypeMatch,
          ktDeviceTypeMatch ? [ktDeviceTypeMatch] : [],
          (term) => this.onDeviceTypeSearch(term),
          {
            hint: isDefined(deviceTypeName)
              ? `CypherView type: "${deviceTypeName}"`
              : undefined,
            props: this.acFieldProps('Search device types in Key Telematics…'),
          },
        ),
      );
    }

    return { deviceMeta, deviceTypeOverrideMeta, fields };
  }

  private acFieldProps(placeholder: string) {
    return {
      field: 'name',
      appendTo: 'body',
      placeholder,
      completeOnFocus: true,
      typeahead: true,
      showEmptyMessage: true,
      emptyMessage: 'No results found',
      forceSelection: true,
    };
  }

  private updateDepFieldSuggestions(
    depType: DepType,
    results: { id: string; name: string }[],
  ): void {
    // assetType/costCentre use their depType as field key; group→groups, category→categories
    const fieldKeyMap: Record<DepType, string> = {
      assetType: 'assetType',
      costCentre: 'costCentre',
      group: 'groups',
      category: 'categories',
    };
    const targetKey = fieldKeyMap[depType];
    for (const field of this.depFormFields) {
      if (field.key === targetKey && field.props) {
        field.props = { ...field.props, suggestions: results };
      }
    }
  }

  private updateDeviceFieldSuggestions(
    results: { id: string; name: string }[],
  ): void {
    const keys = new Set(this.deviceSelectionMeta.map((m) => m.fieldKey));
    for (const field of this.depFormFields) {
      if (keys.has(field.key) && field.props) {
        field.props = { ...field.props, suggestions: results };
      }
    }
  }

  private updateDeviceTypeFieldSuggestions(
    results: { id: string; name: string }[],
  ): void {
    const keys = new Set(this.deviceTypeOverrideMeta.map((m) => m.fieldKey));
    for (const field of this.depFormFields) {
      if (keys.has(field.key) && field.props) {
        field.props = { ...field.props, suggestions: results };
      }
    }
  }

  onFormReady(form: FormGroup): void {
    form
      .get('client')
      ?.valueChanges.pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((client: ClientListItem | null) => {
        this.onClientSelected(client);
      });
  }

  onDepFormReady(form: FormGroup): void {
    // Capture pre-populated values immediately — valueChanges won't fire for initial values
    this.applyDepFormValues(form.getRawValue() as Record<string, unknown>);

    form.valueChanges
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((values: Record<string, unknown>) => {
        this.applyDepFormValues(values);
      });
  }

  private applyDepFormValues(values: Record<string, unknown>): void {
    const allKeys = this.depFormFields.map((f) => f.key);
    if (!allKeys.every((k) => k in values)) return;

    // assetType / costCentre → resolvedIds
    const newResolved: ResolvedIds = new Map();
    for (const meta of this.depFieldMeta) {
      const selected = values[meta.fieldKey] as {
        id: string;
        name: string;
      } | null;
      if (selected !== null && isDefined(selected?.id)) {
        newResolved.set(`${meta.depType}:${meta.sourceName}`, selected.id);
      }
    }
    this.resolvedIds = newResolved;

    // groups / categories → flat arrays of KT objects
    const groupsRaw = values['groups'];
    this.ktGroups = Array.isArray(groupsRaw)
      ? (groupsRaw as { id: string; name: string }[])
      : [];

    const categoriesRaw = values['categories'];
    this.ktCategories = Array.isArray(categoriesRaw)
      ? (categoriesRaw as { id: string; name: string }[])
      : [];

    // device selections / type overrides (optional — don't gate the step)
    const newDeviceSelections: KtDeviceSelections = new Map();
    for (const meta of this.deviceSelectionMeta) {
      const selected = values[meta.fieldKey] as {
        id: string;
        name: string;
      } | null;
      if (selected !== null && isDefined(selected?.id)) {
        newDeviceSelections.set(meta.cvDeviceId, selected.id);
      }
    }
    this.ktDeviceSelections = newDeviceSelections;

    const newDeviceTypeOverrides: KtDeviceTypeOverrides = new Map();
    for (const meta of this.deviceTypeOverrideMeta) {
      const selected = values[meta.fieldKey] as {
        id: string;
        name: string;
      } | null;
      if (selected !== null && isDefined(selected?.id)) {
        newDeviceTypeOverrides.set(meta.cvDeviceId, selected.id);
      }
    }
    this.ktDeviceTypeOverrides = newDeviceTypeOverrides;

    // device type is required on create — every device must have one selected
    const allDeviceTypesResolved = this.deviceTypeOverrideMeta.every((meta) =>
      newDeviceTypeOverrides.has(meta.cvDeviceId),
    );
    const allResolved =
      newResolved.size >= this.depFieldMeta.length && allDeviceTypesResolved;
    this.steps.update((s) =>
      s.map((step) =>
        step.value === 3 ? { ...step, disableNext: !allResolved } : step,
      ),
    );
  }

  onClientSearch(term: string): void {
    this.clientSearchResults.set(undefined);
    this.clientSearchSubject.next(term);
  }

  onClientSelected(client: ClientListItem | null): void {
    this.selectedClient.set(client);
    this.steps.update((s) =>
      s.map((step) =>
        step.value === 2 ? { ...step, disableNext: !client } : step,
      ),
    );
  }

  onDepSearch(depType: DepType, term: string): void {
    const subjectMap: Record<DepType, Subject<string>> = {
      assetType: this.assetTypeSearch$,
      costCentre: this.costCentreSearch$,
      group: this.groupSearch$,
      category: this.categorySearch$,
    };
    subjectMap[depType].next(term);
  }

  onKtDeviceSearch(term: string): void {
    this.ktDeviceSearch$.next(term);
  }

  onDeviceTypeSearch(term: string): void {
    this.deviceTypeSearch$.next(term);
  }

  onWizardComplete(): void {
    const client = this.selectedClient();
    const asset =
      this.entityStateService.selectedItem() as AssetResponse | null;

    if (!client || !asset) return;

    this.isChecking.set(true);
    this.stage.set('confirm');
    this.cdr.detectChanges();

    this.keySyncService
      .checkEntities(
        asset,
        this.assetDevices(),
        client.id,
        this.ktDeviceSelections,
        this.ktDeviceTypeOverrides,
      )
      .subscribe({
        next: (plan) => {
          this.syncPlan.set(plan);
          this.isChecking.set(false);
          this.cdr.detectChanges();
        },
        error: () => {
          this.syncPlan.set(null);
          this.isChecking.set(false);
          this.cdr.detectChanges();
        },
      });
  }

  onConfirmSync(): void {
    const plan = this.syncPlan();
    const client = this.selectedClient();

    if (!plan || !client) return;

    this.stage.set('syncing');
    this.cdr.detectChanges();

    this.keySyncService
      .syncAsset(
        plan,
        client.id,
        this.resolvedIds,
        this.ktDeviceTypeOverrides,
        this.ktGroups,
        this.ktCategories,
      )
      .subscribe({
        next: (result) => {
          this.syncResult.set(result);
          this.stage.set('result');
          this.cdr.detectChanges();
        },
        error: () => {
          this.syncResult.set({
            success: false,
            message: 'An unexpected error occurred during sync.',
          });
          this.stage.set('result');
          this.cdr.detectChanges();
        },
      });
  }

  async onSelectAccount(user: AuthUserResponse): Promise<void> {
    this.isSelectingAccount.set(true);
    this.loginError.set(null);
    try {
      await firstValueFrom(this.keySyncService.selectAccount(user));
      this.loginStage.set('connected');
      this.steps.update((s) =>
        s.map((step) =>
          step.value === 1 ? { ...step, disableNext: false } : step,
        ),
      );
    } catch {
      this.loginError.set('Failed to select account. Please try again.');
    } finally {
      this.isSelectingAccount.set(false);
      this.cdr.detectChanges();
    }
  }

  switchAccount(): void {
    this.loginStage.set('account-select');
    this.selectedClient.set(null);
    this.steps.update((s) =>
      s.map((step) => {
        if (step.value === 1) return { ...step, disableNext: true };
        if (step.value === 2) return { ...step, disableNext: true };
        return step;
      }),
    );
  }

  reAuthenticate(): void {
    this.keySyncService.clearToken();
    this.loginStage.set('credentials');
    this.ktAccounts.set([]);
    this.loginError.set(null);
    this.selectedClient.set(null);
    this.steps.update((s) =>
      s.map((step) => {
        if (step.value === 1)
          return { ...step, disableNext: !this.credForm.valid };
        if (step.value === 2) return { ...step, disableNext: true };
        return step;
      }),
    );
  }

  onBackToWizard(): void {
    this.syncPlan.set(null);
    this.stage.set('wizard');
  }

  onWizardCancel(): void {
    this.dialogRef.close();
  }

  onCancelSync(): void {
    this.dialogRef.close();
  }

  onClose(): void {
    this.dialogRef.close(this.syncResult());
  }

  get hasConflicts(): boolean {
    return (
      this.syncPlan()?.entityChecks.some((c) => c.conflict === true) ?? false
    );
  }

  checkLabel(check: EntityCheckItem): string {
    if (check.conflict === true) return 'Conflict';
    return check.existingId === null ? 'Create' : 'Update';
  }

  checkSeverity(check: EntityCheckItem): 'danger' | 'warn' | 'success' {
    if (check.conflict === true) return 'danger';
    return check.existingId === null ? 'success' : 'warn';
  }
}
